namespace sv_b022ea7c140d4210b54d476218dda72d.Services;

public class RecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 25),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg, and pecorino romano.", 20),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 30),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a spiced tomato and cream sauce.", 45),
            new(5, "Palak Paneer", "Fresh spinach cooked with cubes of paneer cheese.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and herbs.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Vinegared rice with fresh fish wrapped in nori seaweed.", 40),
            new(8, "Ramen", "Rich pork broth with noodles, soft-boiled egg, and chashu.", 50),
            new(9, "Tempura", "Light and crispy battered vegetables and shrimp.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject RecipeService RecipeService
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (error is not null)
{
    <div class="alert alert-danger">
        <p>@error</p>
        <button class="btn btn-outline-danger" @onclick="LoadAsync">Retry</button>
    </div>
}
else if (recipes is null)
{
    <p><em>Loading recipesтАж</em></p>
}
else
{
    @if (isLoading)
    {
        <p><em>RefreshingтАж</em></p>
    }

    @foreach (var recipe in GetSortedRecipes())
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">@recipe.Title</h5>
                <p class="card-text">@recipe.Description</p>
                <p class="card-text"><small class="text-muted">Prep time: @recipe.PrepTimeMinutes min</small></p>
            </div>
        </div>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private CancellationTokenSource? cts;
    private int? loadedCuisineId;
    private List<Recipe>? recipes;
    private bool isLoading;
    private string? error;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == loadedCuisineId)
        {
            return;
        }

        loadedCuisineId = CuisineId;
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }

        cts = new CancellationTokenSource();
        var cancellationToken = cts.Token;

        error = null;
        isLoading = true;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);
            recipes = result;
        }
        catch (OperationCanceledException ex) when (!cancellationToken.IsCancellationRequested)
        {
            Logger.LogWarning(ex, "Timed out loading recipes for cuisine {CuisineId}", CuisineId);
            error = "The request timed out. Please try again.";
        }
        catch (OperationCanceledException)
        {
            // Self-cancellation (parameter change or disposal) тАФ do nothing
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}", CuisineId);
            error = "Unable to load recipes. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (recipes is null) return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => recipes.OrderByDescending(r => r.Id),
            "popular" => recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => recipes,
        };
    }

    public async ValueTask DisposeAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }
    }
}

